// MARK: - Shadow ViewModifiers

private struct TokenShadowModifier: ViewModifier {
    let token: Shadows.ShadowToken
    func body(content: Content) -> some View {
        content.shadow(color: token.color, radius: token.radius, x: token.x, y: token.y)
    }
}

public extension View {
    /// Applies the resting card shadow (sm elevation).
    func cardShadow() -> some View { modifier(TokenShadowModifier(token: Shadows.sm)) }
    /// Applies the elevated / active-state shadow (md elevation).
    func elevatedShadow() -> some View { modifier(TokenShadowModifier(token: Shadows.md)) }
    /// Applies the floating / modal shadow (lg elevation).
    func floatingShadow() -> some View { modifier(TokenShadowModifier(token: Shadows.lg)) }
}
